// OmniScore API Routes
const express = require('express');
const { authMiddleware } = require('../lib/auth');
const omniscoreService = require('../services/omniscore');
const { AuditLogger } = require('../services/auditLogger');

const router = express.Router();

// Get current OmniScore
router.get('/', authMiddleware, async (req, res) => {
  try {
    const score = await omniscoreService.getOrCreateScore(req.user.id);
    const currentScores = await omniscoreService.calculateScore(req.user.id);

    // Audit log: Score calculation
    await AuditLogger.log({
      actionType: 'omniscore_calculated',
      userId: req.user.id,
      targetType: 'omniscore',
      targetId: score.id,
      metadata: {
        overall_score: currentScores.total_score,
        technical: currentScores.technical_score,
        behavioral: currentScores.behavioral_score,
        experience: currentScores.experience_score
      },
      req
    });

    res.json({
      success: true,
      omniscore: currentScores
    });
  } catch (err) {
    console.error('Get OmniScore error:', err);
    res.status(500).json({ error: 'Failed to get OmniScore' });
  }
});

// Get detailed score breakdown
router.get('/breakdown', authMiddleware, async (req, res) => {
  try {
    const breakdown = await omniscoreService.getScoreBreakdown(req.user.id);

    res.json({
      success: true,
      ...breakdown
    });
  } catch (err) {
    console.error('Get score breakdown error:', err);
    res.status(500).json({ error: 'Failed to get score breakdown' });
  }
});

// Get role-specific scores
router.get('/roles', authMiddleware, async (req, res) => {
  try {
    const roleScores = await omniscoreService.getRoleScores(req.user.id);

    res.json({
      success: true,
      role_scores: roleScores
    });
  } catch (err) {
    console.error('Get role scores error:', err);
    res.status(500).json({ error: 'Failed to get role scores' });
  }
});

// Get score history
router.get('/history', authMiddleware, async (req, res) => {
  try {
    const pool = require('../lib/db');
    const { limit = 20 } = req.query;

    const result = await pool.query(`
      SELECT previous_score, new_score, change_amount, change_reason, component_type, created_at
      FROM score_history
      WHERE user_id = $1
      ORDER BY created_at DESC
      LIMIT $2
    `, [req.user.id, limit]);

    res.json({
      success: true,
      history: result.rows
    });
  } catch (err) {
    console.error('Get score history error:', err);
    res.status(500).json({ error: 'Failed to get score history' });
  }
});

// Get recommendations to improve score
router.get('/recommendations', authMiddleware, async (req, res) => {
  try {
    const currentScores = await omniscoreService.calculateScore(req.user.id);
    const recommendations = omniscoreService.generateRecommendations(currentScores);

    res.json({
      success: true,
      current_score: currentScores.total_score,
      recommendations
    });
  } catch (err) {
    console.error('Get recommendations error:', err);
    res.status(500).json({ error: 'Failed to get recommendations' });
  }
});

// Record daily login (behavior component)
router.post('/checkin', authMiddleware, async (req, res) => {
  try {
    const pool = require('../lib/db');

    // Check if already checked in today
    const today = await pool.query(`
      SELECT id FROM score_components
      WHERE user_id = $1
        AND component_type = 'behavior'
        AND source_type = 'daily_login'
        AND DATE(created_at) = CURRENT_DATE
    `, [req.user.id]);

    if (today.rows.length > 0) {
      return res.json({ success: true, already_checked_in: true });
    }

    // Add daily login points
    const newScore = await omniscoreService.addBehaviorComponent(
      req.user.id,
      'daily_login',
      5, // 5 points per daily login
      10
    );

    // Audit log: Daily check-in
    await AuditLogger.log({
      actionType: 'daily_checkin',
      userId: req.user.id,
      targetType: 'score_component',
      metadata: {
        points_earned: 5,
        new_total_score: newScore.total_score
      },
      req
    });

    res.json({
      success: true,
      new_score: newScore.total_score,
      points_earned: 5
    });
  } catch (err) {
    console.error('Checkin error:', err);
    res.status(500).json({ error: 'Failed to record check-in' });
  }
});

module.exports = router;

// OmniScore Migration - Candidate Credit Score System
module.exports = {
  name: 'add_omniscore_tables',
  up: async (client) => {
    // OmniScore main table - stores current score and history
    await client.query(`
      CREATE TABLE IF NOT EXISTS omni_scores (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE UNIQUE,
        total_score INTEGER DEFAULT 300,
        interview_score INTEGER DEFAULT 0,
        technical_score INTEGER DEFAULT 0,
        resume_score INTEGER DEFAULT 0,
        behavior_score INTEGER DEFAULT 0,
        score_tier VARCHAR(50) DEFAULT 'new',
        last_updated TIMESTAMP DEFAULT NOW(),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Score components - individual score factors with time decay
    await client.query(`
      CREATE TABLE IF NOT EXISTS score_components (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        component_type VARCHAR(50) NOT NULL,
        source_type VARCHAR(50),
        source_id INTEGER,
        points INTEGER NOT NULL,
        max_points INTEGER NOT NULL,
        weight DECIMAL(3,2) DEFAULT 1.0,
        decay_rate DECIMAL(3,2) DEFAULT 0.95,
        metadata JSONB DEFAULT '{}',
        created_at TIMESTAMP DEFAULT NOW(),
        expires_at TIMESTAMP
      )
    `);

    // Score history - track score changes over time
    await client.query(`
      CREATE TABLE IF NOT EXISTS score_history (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        previous_score INTEGER,
        new_score INTEGER,
        change_amount INTEGER,
        change_reason VARCHAR(255),
        component_type VARCHAR(50),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Role-specific scores
    await client.query(`
      CREATE TABLE IF NOT EXISTS role_scores (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        role_name VARCHAR(100) NOT NULL,
        score INTEGER DEFAULT 300,
        interview_count INTEGER DEFAULT 0,
        last_updated TIMESTAMP DEFAULT NOW(),
        UNIQUE(user_id, role_name)
      )
    `);

    // Create indexes for performance
    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_score_components_user ON score_components(user_id);
      CREATE INDEX IF NOT EXISTS idx_score_history_user ON score_history(user_id);
      CREATE INDEX IF NOT EXISTS idx_role_scores_user ON role_scores(user_id);
    `);

    console.log('OmniScore tables created successfully');
  }
};

