   332→      const numAxes = categoryData.length;
   333→
   334→      if (numAxes < 3) {
   335→        // Not enough categories for radar - show bar chart instead
   336→        container.innerHTML = `
   337→          <div class="skills-bars">
   338→            ${categoryData.map(cat => {
   339→              const label = formatCategoryName(cat.name);
   340→              return `
   341→                <div class="skill-bar-item">
   342→                  <div class="skill-bar-header">
   343→                    <span class="skill-bar-label">${label}</span>
   344→                    <span class="skill-bar-value">${cat.avg}%</span>
   345→                  </div>
   346→                  <div class="skill-bar-track">
   347→                    <div class="skill-bar-fill" style="width: ${cat.avg}%"></div>
   348→                  </div>
   349→                  <span class="skill-bar-count">${cat.count} skill${cat.count !== 1 ? 's' : ''} ${cat.verified > 0 ? `(${cat.verified} verified)` : ''}</span>
   350→                </div>
   351→              `;
   352→            }).join('')}
   353→          </div>
   354→        `;
   355→        return;
   356→      }
   357→
   358→      const cx = 100, cy = 100, radius = 70;
   359→      const angleStep = (2 * Math.PI) / numAxes;
   360→
   361→      // Calculate points for each level (20%, 40%, 60%, 80%, 100%)
   362→      const levels = [20, 40, 60, 80, 100];
   363→      const levelPolygons = levels.map(level => {
   364→        const r = (level / 100) * radius;
   365→        return categoryData.map((_, i) => {
   366→          const angle = i * angleStep - Math.PI / 2;
   367→          return `${cx + r * Math.cos(angle)},${cy + r * Math.sin(angle)}`;
   368→        }).join(' ');
   369→      });
   370→
   371→      // Calculate data points
   372→      const dataPoints = categoryData.map((cat, i) => {
   373→        const r = (cat.avg / 100) * radius;
   374→        const angle = i * angleStep - Math.PI / 2;
   375→        return `${cx + r * Math.cos(angle)},${cy + r * Math.sin(angle)}`;
   376→      }).join(' ');
   377→
   378→      // Axis lines
   379→      const axisLines = categoryData.map((_, i) => {
   380→        const angle = i * angleStep - Math.PI / 2;
   381→        return `<line x1="${cx}" y1="${cy}" x2="${cx + radius * Math.cos(angle)}" y2="${cy + radius * Math.sin(angle)}" stroke="var(--border-color)" stroke-width="1"/>`;
   382→      }).join('');
   383→
   384→      // Labels
   385→      const labels = categoryData.map((cat, i) => {
   386→        const angle = i * angleStep - Math.PI / 2;
   387→        const labelRadius = radius + 25;
   388→        const x = cx + labelRadius * Math.cos(angle);
   389→        const y = cy + labelRadius * Math.sin(angle);
   390→        const label = formatCategoryName(cat.name);
   391→        return `<text x="${x}" y="${y}" text-anchor="middle" dominant-baseline="middle" class="radar-label">${label}</text>`;
   392→      }).join('');
   393→
   394→      container.innerHTML = `
   395→        <svg viewBox="0 0 200 200" class="radar-svg">
   396→          <!-- Grid levels -->
   397→          ${levelPolygons.map((points, i) => `<polygon points="${points}" fill="none" stroke="var(--border-color)" stroke-width="1" opacity="${0.2 + i * 0.1}"/>`).join('')}
   398→          <!-- Axis lines -->
   399→          ${axisLines}
   400→          <!-- Data polygon -->
   401→          <polygon points="${dataPoints}" fill="url(#radarGradient)" stroke="var(--accent-primary)" stroke-width="2" fill-opacity="0.3"/>
   402→          <!-- Data points -->
   403→          ${categoryData.map((cat, i) => {
   404→            const r = (cat.avg / 100) * radius;
   405→            const angle = i * angleStep - Math.PI / 2;
   406→            const x = cx + r * Math.cos(angle);
   407→            const y = cy + r * Math.sin(angle);
   408→            return `<circle cx="${x}" cy="${y}" r="4" fill="var(--accent-primary)" class="radar-point" data-category="${cat.name}" data-value="${cat.avg}"/>`;
   409→          }).join('')}
   410→          <!-- Labels -->
   411→          ${labels}
   412→          <defs>
   413→            <linearGradient id="radarGradient" x1="0%" y1="0%" x2="100%" y2="100%">
   414→              <stop offset="0%" style="stop-color:#10b981"/>
   415→              <stop offset="100%" style="stop-color:#06b6d4"/>
   416→            </linearGradient>
   417→          </defs>
   418→        </svg>
   419→      `;
   420→    }
