   251→/**
   252→ * Calculate cosine similarity between two vectors
   253→ */
   254→function cosineSimilarity(vecA, vecB) {
   255→  if (!vecA || !vecB || vecA.length !== vecB.length) {
   256→    return 0;
   257→  }
   258→
   259→  let dotProduct = 0;
   260→  let normA = 0;
   261→  let normB = 0;
   262→
   263→  for (let i = 0; i < vecA.length; i++) {
   264→    dotProduct += vecA[i] * vecB[i];
   265→    normA += vecA[i] * vecA[i];
   266→    normB += vecB[i] * vecB[i];
   267→  }
   268→
   269→  const magnitude = Math.sqrt(normA) * Math.sqrt(normB);
   270→  return magnitude === 0 ? 0 : dotProduct / magnitude;
   271→}
