   321→    const result = await pool.query(`
   322→      SELECT
   323→        j.id as job_id, j.title, j.location, j.salary_range, j.job_type,
   324→        c.id as company_id, c.name as company_name, c.logo_url, c.industry, c.is_verified,
   325→        ts.total_score as company_trust_score, ts.score_tier as company_tier,
   326→        ja.status as application_status,
   327→        mr.weighted_score as match_score, mr.match_level,
   328→        COALESCE(
   329→          ROUND(AVG(cr.overall_rating)::numeric, 1),
   330→          0
   331→        ) as avg_company_rating,
   332→        COUNT(cr.id) as rating_count
   333→      FROM jobs j
   334→      JOIN companies c ON j.company_id = c.id
   335→      LEFT JOIN trust_scores ts ON c.id = ts.company_id
   336→      LEFT JOIN job_applications ja ON ja.job_id = j.id AND ja.candidate_id = $1
   337→      LEFT JOIN match_results mr ON mr.job_id = j.id AND mr.candidate_id = $1
   338→      LEFT JOIN company_ratings cr ON cr.company_id = c.id AND cr.status = 'published'
   339→      WHERE j.status = 'active'
   340→        AND (ja.candidate_id = $1 OR mr.candidate_id = $1)
   341→      GROUP BY j.id, j.title, j.location, j.salary_range, j.job_type,
   342→               c.id, c.name, c.logo_url, c.industry, c.is_verified,
   343→               ts.total_score, ts.score_tier, ja.status,
   344→               mr.weighted_score, mr.match_level
   345→      ORDER BY
   346→        COALESCE(mr.weighted_score, 0) + COALESCE(ts.total_score, 0) / 20 DESC
   347→      LIMIT 20
   348→    `, [req.user.id]);
