   355→
   356→      // Mutual fit: geometric mean of all three signals
   357→      const mutualFit = Math.round(
   358→        Math.pow(candidateStrength * companyStrength * matchStrength, 1/3) * 100
   359→      );
   360→
   361→      let mutualLevel = 'low';
   362→      if (mutualFit >= 80) mutualLevel = 'excellent';
   363→      else if (mutualFit >= 65) mutualLevel = 'good';
